// NotificationFactory.java — zero switch, zero if-else
class NotificationFactory {
    private static final Map<String, Supplier<Notification>> registry
        = new HashMap<>();

    static {
        register("email", () -> new EmailNotification("smtp.gmail.com", 587));
        register("sms",   () -> new SMSNotification("+1-API-KEY", "twilio"));
        register("push",  () -> new PushNotification("FCM-KEY", "high"));
    }

    static void register(String type, Supplier<Notification> creator) {
        registry.put(type, creator);
    }

    static Notification create(String type) {
        Supplier<Notification> creator = registry.get(type);
        if (creator == null) throw new IllegalArgumentException("Unknown: " + type);
        return creator.get();
    }
}
