// Abstract service — defines the algorithm skeleton
abstract class NotificationService {
    // Factory Method — subclasses decide WHAT to create
    protected abstract Notification createNotification();

    // Template method — uses the factory method
    void notifyUser(String msg) {
        Notification n = createNotification();  // subclass decides
        n.validate();
        n.send(msg);
        n.log();
    }
}

// Each subclass overrides ONLY the creation part
class EmailNotificationService extends NotificationService {
    protected Notification createNotification() {
        return new EmailNotification("smtp.gmail.com", 587);
    }
}

class SMSNotificationService extends NotificationService {
    protected Notification createNotification() {
        return new SMSNotification("+1-API-KEY", "twilio");
    }
}
